import { moduleMetadata } from '@storybook/angular';
import { PfAvatarComponent } from './avatar.component';
const meta = {
    title: 'Composants/Avatar',
    component: PfAvatarComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Avatar avec image et fallback sur initiales.",
            },
        },
    },
    decorators: [moduleMetadata({ imports: [PfAvatarComponent] })],
    argTypes: {
        size: { control: 'inline-radio', options: ['sm', 'md', 'lg', 'xl'] },
    },
    args: { alt: 'Léonard Tavae', size: 'md' },
    render: (args) => ({
        props: args,
        template: `<pf-avatar
      [src]="src || ''"
      [alt]="alt"
      [initials]="initials || ''"
      [size]="size"
    ></pf-avatar>`,
    }),
};
export default meta;
export const InitialsOnly = {};
export const WithImage = {
    args: { src: 'https://i.pravatar.cc/150?u=leonard' },
};
export const Sizes = {
    render: () => ({
        template: `
      <div style="display: flex; gap: 12px; align-items: center;">
        <pf-avatar alt="Marie Dupont" size="sm"></pf-avatar>
        <pf-avatar alt="Marie Dupont" size="md"></pf-avatar>
        <pf-avatar alt="Marie Dupont" size="lg"></pf-avatar>
        <pf-avatar alt="Marie Dupont" size="xl"></pf-avatar>
      </div>
    `,
    }),
};
export const FallbackOnError = {
    args: {
        src: 'https://this-url-does-not-exist.invalid/avatar.jpg',
        alt: 'Jean Martin',
    },
};
export const ExplicitInitials = {
    args: { alt: 'Direction des Affaires Maritimes', initials: 'DAM' },
};
